using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sub component 1 under root component
    Ptr occs = rootComp->occurrences();
    if (!occs)
        return false;
    Ptr transform = adsk::core::Matrix3D::create();
    if (!transform)
        return false;
    Ptr subOcc0 = occs->addNewComponent(transform);
    if (!subOcc0)
        return false;

    // Create sketch 1 in sub component 1
    Ptr subComp0 = subOcc0->component();
    if (!subComp0)
        return false;
    Ptr sketches0 = subComp0->sketches();
    if (!sketches0)
        return false;
    Ptr xzPlane = rootComp->xZConstructionPlane();
    if (!xzPlane)
        return false;
    Ptr sketch0 = sketches0->add(xzPlane);
    if (!sketch0)
        return false;
    Ptr sketchCurves0 = sketch0->sketchCurves();
    if (!sketchCurves0)
        return false;
    Ptr sketchCircles0 = sketchCurves0->sketchCircles();
    if (!sketchCircles0)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    Ptr sketchCircle0 = sketchCircles0->addByCenterRadius(centerPoint, 2.5);
    if (!sketchCircle0)
        return false;

    // Get the profile defined by the circle
    Ptr profs0 = sketch0->profiles();
    if (!profs0)
        return false;
    Ptr profile0 = profs0->item(0);
    if (!profile0)
        return false;

    // Create an extrude input
    Ptr feats0 = subComp0->features();
    if (!feats0)
        return false;
    Ptr extrudes0 = feats0->extrudeFeatures();
    if (!extrudes0)
        return false;
    Ptr extInput0 = extrudes0->createInput(profile0, FeatureOperations::NewBodyFeatureOperation);
    if (!extInput0)
        return false;

    // Set the extrude input
    Ptr distance0 = ValueInput::createByString("5 mm");
    if (!distance0)
        return false;
    extInput0->setDistanceExtent(false, distance0);
    extInput0->isSolid(true);

    // Create the extrude
    Ptr ext = extrudes0->add(extInput0);
    if (!ext)
        return false;

    // Get the end face of the created extrude
    Ptr endFaces = ext->endFaces();
    if (!endFaces)
        return false;
    Ptr endFace = endFaces->item(0);
    if (!endFace)
        return false;

    // Create a construction plane for extrude 2
    Ptr ctorPlanes = subComp0->constructionPlanes();
    if (!ctorPlanes)
        return false;
    Ptr ctorPlaneInput = ctorPlanes->createInput();
    if (!ctorPlaneInput)
        return false;
    ctorPlaneInput->setByOffset(endFace, adsk::core::ValueInput::createByString("20 mm"));
    Ptr ctorPlane = ctorPlanes->add(ctorPlaneInput);
    if (!ctorPlane)
        return false;
    Ptr ctorPlaneProxy = ctorPlane->createForAssemblyContext(subOcc0);
    if (!ctorPlaneProxy)
        return false;

    // Create sub component 2 under root component
    Ptr subOcc1 = occs->addNewComponent(transform);
    if (!subOcc1)
        return false;

    // Create sketch 2 in sub component 2
    Ptr subComp1 = subOcc1->component();
    if (!subComp1)
        return false;
    Ptr sketches1 = subComp1->sketches();
    if (!sketches1)
        return false;
    Ptr sketch1 = sketches1->add(ctorPlaneProxy);
    if (!sketch1)
        return false;
    Ptr sketchCurves1 = sketch1->sketchCurves();
    if (!sketchCurves1)
        return false;
    Ptr sketchCircles1 = sketchCurves1->sketchCircles();
    if (!sketchCircles1)
        return false;
    Ptr sketchCircle1 = sketchCircles1->addByCenterRadius(centerPoint, 0.5);
    if (!sketchCircle1)
        return false;

    // Get the profile defined by the circle
    Ptr profs1 = sketch1->profiles();
    if (!profs1)
        return false;
    Ptr profile1 = profs1->item(0);
    if (!profile1)
        return false;

    // Create an extrude input
    Ptr feats1 = subComp1->features();
    if (!feats1)
        return false;
    Ptr extrudes1 = feats1->extrudeFeatures();
    if (!extrudes1)
        return false;
    Ptr extInput1 = extrudes1->createInput(profile1, FeatureOperations::NewBodyFeatureOperation);
    if (!extInput1)
        return false;

    // Set the extrude input
    Ptr distance1 = ValueInput::createByString("50 mm");
    if (!distance1)
        return false;
    extInput1->setDistanceExtent(false, distance1);
    extInput1->isSolid(false);

    // Create the extrude
    Ptr extrude1 = extrudes1->add(extInput1);
    if (!extrude1)
        return false;

    // Create the AsBuiltJoint
    Ptr asBuiltJoints_ = rootComp->asBuiltJoints();
    if (!asBuiltJoints_)
        return false;
    Ptr asBuiltJointInput = asBuiltJoints_->createInput(subOcc0, subOcc1, nullptr);
    if (!asBuiltJointInput)
        return false;
    Ptr asBuiltJoint = asBuiltJoints_->add(asBuiltJointInput);
    if (!asBuiltJoint)
        return false;

    // Fit to window
    Ptr viewPort = app->activeViewport();
    if (!viewPort)
        return false;
    Ptr cam = viewPort->camera();
    if (!cam)
        return false;
    cam->isFitView(true);
    viewPort->camera(cam);


    return true;
}
